// আপনার ইনপুট স্ট্রাকচার অনুযায়ী সরাসরি প্রপার্টি অ্যাক্সেস করা হয়েছে
const body = $json.body || $json; // Webhook-এর বডি থেকে ডেটা নেওয়া হচ্ছে

const entry = body.entry && body.entry[0];
const changes = entry && entry.changes && entry.changes[0];
const value = changes && changes.value;

if (!value) {
    return [{ error: "No comment data found in input" }];
}

return [{
  sender_id: value.from ? value.from.id : null,
  sender_name: value.from ? value.from.name : "Unknown",
  comment_text: value.message || "",
  comment_id: value.comment_id,
  post_id: value.post_id
}];

